fn main() {
    let mut data = Vec::<i32>::new();
    data.push(1);
    data.push(2);

    // Partial move: We only take ownership of the first element's contents, 
    // leaving the rest of the vector intact.
    let (first_element, remaining_elements) = data.split_at(1);

    if let Some(first) = first_element.get(0) {
        println!("Successfully moved/copied first element: {}", first);
    }

    // We can still use the rest of the vector because only the prefix was 'moved' out.
    println!("Remaining elements count: {}", remaining_elements.len());
}

struct DataContainer {
    numbers: Vec<i32>,
    metadata: String,
}

// This function only needs to read the numbers, so it takes a reference.
fn process_numbers(data: &DataContainer) -> i32 {
    println!("Inside function: Reading metadata (read-only access)");
    data.metadata.len() as i32 + data.numbers.iter().sum::<i32>()
}

fn main() {
    // Create the initial structure
    let original_data = DataContainer {
        numbers: vec![10, 20, 5],
        metadata: String::from("Initial state data")
    };

    println!("Main: Before calling process_numbers. Metadata length: {}", original_data.metadata.len());

    // Pass a reference (&) to the entire structure.
    let result = process_numbers(&original_data);

    println!("Main: Function returned successfully. Result: {}", result);

    // Because we only passed a reference, we can still use original_data freely.
    println!("Main: After calling function. Metadata length is still: {}", original_data.metadata.len());
}

use std::collections::HashMap;

// Represents some large chunk of data we own.
struct DataSet {
    data: HashMap<String, String>,
}

impl DataSet {
    fn new() -> Self {
        DataSet { 
            data: HashMap::new() 
        }
    }

    // This function only needs to look at one key-value pair from the data.
    // It takes a reference, so it doesn't move ownership.
    fn process_single_item(&self, key: &str) -> Option<&String> {
        self.data.get(key).map(|s| s)
    }

    // This function needs to extract one specific piece of data and give it away,
    // but we want to keep the rest of the DataSet intact.
    fn remove_and_return(&mut self, key: &str) -> Option<String> {
        self.data.remove(key)
    }
}

fn main() {
    let mut dataset = DataSet::new();
    dataset.data.insert("user_id".to_string(), "12345".to_string());
    dataset.data.insert("report_name".to_string(), "Quarterly".to_string());

    // 1. Reading without moving (Borrowing)
    if let Some(item) = dataset.process_single_item("user_id") {
        println!("Successfully viewed user ID: {}", item);
    }

    // 2. Taking ownership of a piece while keeping the container usable (Partial Move via API)
    let key_to_extract = "report_name".to_string();
    match dataset.remove_and_return(&key_to_extract) {
        Some(report) => println!("Extracted report name: {}", report),
        None => println!("Could not find report name.")
    }

    // We can still use the rest of the data in 'dataset' even though we removed one key.
    println!("Remaining items count: {}", dataset.data.len());
}

struct Person {
    name: String,
    phone_number: Option<String>,
}

impl Person {
    fn new(name: &str) -> Self {
        Person {
            name: String::from(name),
            phone_number: None,
        }
    }

    // This function accepts a reference to the struct, ensuring ownership is not moved.
    fn print_details(&self) {
        println!("Name: {}", self.name);
        match &self.phone_number {
            Some(phone) => println!("Phone: {}", phone),
            None => println!("Phone: Not provided"),
        }
    }
}

fn main() {
    // Create the initial instance.
    let alice = Person::new("Alice");

    // We pass a reference (&alice) to the function. 
    // This allows the function to read the data without consuming it.
    alice.print_details();

    // Because we only passed a reference, 'alice' is still usable here.
    println!("\nSuccessfully used alice again after passing a reference.");
}

struct DataBundle {
    description: String,
    scores: Vec<i32>,
}

// This function only needs to read the description and one score.
fn process_bundle(bundle: &DataBundle) -> i32 {
    println!("Processing bundle with description: {}", bundle.description);
    if let Some(&score) = bundle.scores.get(0) {
        return score;
    } else {
        return 0;
    }
}

fn main() {
    let my_data = DataBundle {
        description: String::from("Results for the week"),
        scores: vec![95, 88, 72],
    };

    // Passing a reference (&) allows us to read parts without moving or consuming the whole thing.
    let result = process_bundle(&my_data);
    println!("The resulting score is: {}", result);

    // We can still use my_data here because we only passed a reference, not ownership.
    println!("We can confirm the data bundle is still usable after the function call.");
}
